// SNOWBALLING_v2 (v0.2.9) - chainage de citations multi-sources
// Sources : OpenAlex (cited_by/cites), Semantic Scholar (references/citations),
// Europe PMC (references/citations), OpenCitations COCI (references/citations, enrichi via OpenAlex).
// Backward = references ; Forward = citations. Dedup vs corpus + entre sources (provenance _snowball_sources).
const PROXY = 'http://host.docker.internal:3456';
const items = $input.all();
const seeds = items.map(i => i.json);
const seed0 = seeds[0] || {};

let DIRECTIONS = 'both';
let FWD_CAP = 100;
let SOURCES = ['openalex','semanticscholar','europepmc','opencitations'];
try {
  const cfg = await this.helpers.httpRequest({ method:'GET', url:'http://host.docker.internal:8080/api/config', timeout:5000, json:true }) || {};
  if (cfg.snowball_directions === 'backward' || cfg.snowball_directions === 'forward' || cfg.snowball_directions === 'both') DIRECTIONS = cfg.snowball_directions;
  if (typeof cfg.snowball_forward_cap === 'number' && cfg.snowball_forward_cap > 0) FWD_CAP = Math.min(cfg.snowball_forward_cap, 200);
  if (Array.isArray(cfg.snowball_sources) && cfg.snowball_sources.length) SOURCES = cfg.snowball_sources;
} catch(e) {}
if (Array.isArray(seed0._snowball_sources_override) && seed0._snowball_sources_override.length) SOURCES = seed0._snowball_sources_override;
const SRC = {}; SOURCES.forEach(function(s){ SRC[s]=true; });
SRC.openalex = true; // OpenAlex toujours actif (resolution + enrichissement OpenCitations)

const OA_SELECT = 'id,doi,display_name,publication_year,authorships,primary_location,cited_by_count,abstract_inverted_index';
const doBack = (DIRECTIONS === 'both' || DIRECTIONS === 'backward');
const doFwd  = (DIRECTIONS === 'both' || DIRECTIONS === 'forward');

function norm(t){ return (t||'').toString().toLowerCase().replace(/[^a-z0-9]+/g,' ').trim(); }
function cleanDoi(d){ return (d||'').toString().toLowerCase().replace(/^https?:\/\/(dx\.)?doi\.org\//,'').trim(); }
function recon(inv){ if(!inv) return ''; const w=[]; for(const k in inv){ const ps=inv[k]; for(let i=0;i<ps.length;i++){ w[ps[i]]=k; } } return w.join(' ').replace(/\s+/g,' ').trim().substring(0,2000); }
let __oaLast = 0; const get = async (url) => { const isOA = url.indexOf('api.openalex.org') >= 0; if (isOA) { url += (url.indexOf('?')>=0?'&':'?') + 'mailto=ultralab-review@systematic-review.org'; /* OA_POLITE_POOL_v1 */ /* OA_THROTTLE_v1 : espace les appels (>=120ms) + retry backoff sur 429/echec (bug B2) */ const w = 120 - (Date.now() - __oaLast); if (w > 0) await new Promise(function(r){ setTimeout(r, w); }); } let attempt = 0; while (true) { try { const r = await this.helpers.httpRequest({ method:'GET', url: PROXY + '?url=' + encodeURIComponent(url), json:true, timeout:40000 }); if (isOA) __oaLast = Date.now(); return r; } catch(e) { attempt++; if (!isOA || attempt >= 3) { if (isOA) __oaLast = Date.now(); return null; } const code = (e && (e.statusCode || (e.response && e.response.statusCode))) || 0; const delay = (code === 429 ? 1500 : 600) * attempt; await new Promise(function(r){ setTimeout(r, delay); }); } } };

function mapOA(w){ if(!w) return null; const authors=(w.authorships||[]).map(a=>a.author && a.author.display_name).filter(Boolean); const journal=(w.primary_location && w.primary_location.source && w.primary_location.source.display_name)||''; return { title:w.display_name||'', doi:cleanDoi(w.doi), year:w.publication_year?String(w.publication_year):'', authors:authors, journal:journal, abstract:recon(w.abstract_inverted_index), cited_by_count:w.cited_by_count||0, openalex_id:w.id||'' }; }
function mapS2(p){ if(!p) return null; const ex=p.externalIds||{}; return { title:p.title||'', doi:cleanDoi(ex.DOI||''), year:p.year?String(p.year):'', authors:(p.authors||[]).map(function(a){return a.name;}).filter(Boolean), journal:p.venue||'', abstract:p.abstract||'', cited_by_count:p.citationCount||0 }; }
function mapEPMC(it){ if(!it) return null; return { title:it.title||'', doi:cleanDoi(it.doi||''), year:it.pubYear?String(it.pubYear):'', authors:(it.authorString||'').split(/,\s*/).filter(Boolean), journal:it.journalAbbreviation||'', abstract:'', cited_by_count:it.citedByCount||0 }; }

const corpusDoi = new Set(), corpusTitle = new Set();
for (const s of seeds){ const d=cleanDoi(s.doi); if(d) corpusDoi.add(d); const t=norm(s.title); if(t) corpusTitle.add(t); }

const summary = { seeds: seeds.length, seeds_resolved: 0, by_source: {}, candidates_unique: 0, removed_in_corpus: 0, directions: DIRECTIONS, forward_cap: FWD_CAP, sources: SOURCES.slice() };
SOURCES.forEach(function(s){ summary.by_source[s]={backward:0,forward:0}; });
const store = {}; const doiIndex = {}; const titleIndex = {}; let _cid = 0;

function addCandidate(art, direction, seedLabel, source){
  if (!art || (!art.title && !art.doi)) return;
  const nt = norm(art.title);
  if ((art.doi && corpusDoi.has(art.doi)) || (nt && corpusTitle.has(nt))){ summary.removed_in_corpus++; return; }
  if (summary.by_source[source]) summary.by_source[source][direction] = (summary.by_source[source][direction]||0)+1;
  // fusion inter-sources : par DOI, sinon par titre normalise
  let id = null;
  if (art.doi && doiIndex[art.doi]!=null) id = doiIndex[art.doi];
  else if (nt && titleIndex[nt]!=null) id = titleIndex[nt];
  if (id===null){
    id = ++_cid;
    art._snowball_direction = direction; art._snowball_seeds=[seedLabel]; art._snowball_seed_count=1; art._snowball_sources=[source]; art.source='snowball';
    store[id]=art;
    if (art.doi) doiIndex[art.doi]=id;
    if (nt) titleIndex[nt]=id;
  } else {
    const ex=store[id];
    if (ex._snowball_direction !== direction) ex._snowball_direction='both';
    if (ex._snowball_seeds.indexOf(seedLabel)<0){ ex._snowball_seeds.push(seedLabel); ex._snowball_seed_count++; }
    if (ex._snowball_sources.indexOf(source)<0) ex._snowball_sources.push(source);
    if (!ex.abstract && art.abstract) ex.abstract=art.abstract;
    if (!ex.doi && art.doi){ ex.doi=art.doi; doiIndex[art.doi]=id; }
    if (!ex.title && art.title){ ex.title=art.title; if(nt) titleIndex[nt]=id; }
  }
}

async function enrichDois(dois, direction, seedLabel){
  for (let i=0;i<dois.length;i+=50){
    const batch = dois.slice(i,i+50).filter(Boolean);
    if (!batch.length) continue;
    const url = 'https://api.openalex.org/works?filter=doi:' + batch.join('|') + '&per_page=50&select=' + OA_SELECT;
    const r = await get(url);
    if (r && r.results){ for (const w of r.results) addCandidate(mapOA(w), direction, seedLabel, 'opencitations'); }
  }
}

for (let si=0; si<seeds.length; si++){
  const s = seeds[si];
  // SNOWBALL_PROGRESS_v1 : avancement temps reel (reseau, pas de LLM -> tick explicite)
  if (si % 5 === 0 || si === seeds.length - 1) { try { await this.helpers.httpRequest({ method:'POST', url:'http://host.docker.internal:8080/api/module-progress/tick', body: JSON.stringify({ current: si+1, total: seeds.length, label:'snowballing' }), headers:{'Content-Type':'application/json'}, timeout:5000 }); } catch(e) {} }
  const seedLabel = (s.title || s.doi || ('seed#'+(si+1))).toString().substring(0,80);
  const sd = cleanDoi(s.doi);
  let resolvedAny = false;

  // OpenAlex
  if (SRC.openalex){
    let wid='';
    if (sd){ const w=await get('https://api.openalex.org/works/https://doi.org/'+sd); if(w&&w.id) wid=w.id; }
    if (!wid && s.title){ const sr=await get('https://api.openalex.org/works?filter=title.search:'+encodeURIComponent(s.title.replace(/[,:]/g,' ').substring(0,120)) /*LOTB_SNOW_COMMA_v1*/+'&per_page=1'); if(sr&&sr.results&&sr.results[0]&&sr.results[0].id) wid=sr.results[0].id; }
    if (wid){ resolvedAny=true; const id=wid.split('/').pop();
      if (doBack){ const b=await get('https://api.openalex.org/works?filter=cited_by:'+id+'&per_page=200&select='+OA_SELECT); if(b&&b.results){ for(const w of b.results) addCandidate(mapOA(w),'backward',seedLabel,'openalex'); } }
      if (doFwd){ const f=await get('https://api.openalex.org/works?filter=cites:'+id+'&per_page='+Math.min(FWD_CAP,200)+'&sort=cited_by_count:desc&select='+OA_SELECT); if(f&&f.results){ for(const w of f.results) addCandidate(mapOA(w),'forward',seedLabel,'openalex'); } }
    }
  }

  // Semantic Scholar (par DOI, best-effort, rate-limite sans cle -> 1 retry)
  if (SRC.semanticscholar && sd){
    const base='https://api.semanticscholar.org/graph/v1/paper/DOI:'+sd;
    if (doBack){ let r=await get(base+'/references?fields=title,year,externalIds,authors,venue,citationCount,abstract&limit=200'); if(!(r&&r.data)) r=await get(base+'/references?fields=title,year,externalIds,authors,venue,citationCount,abstract&limit=200'); if(r&&r.data){ resolvedAny=true; for(const e of r.data){ if(e.citedPaper) addCandidate(mapS2(e.citedPaper),'backward',seedLabel,'semanticscholar'); } } }
    if (doFwd){ let r=await get(base+'/citations?fields=title,year,externalIds,authors,venue,citationCount,abstract&limit='+Math.min(FWD_CAP,1000)); if(!(r&&r.data)) r=await get(base+'/citations?fields=title,year,externalIds,authors,venue,citationCount,abstract&limit='+Math.min(FWD_CAP,1000)); if(r&&r.data){ resolvedAny=true; for(const e of r.data){ if(e.citingPaper) addCandidate(mapS2(e.citingPaper),'forward',seedLabel,'semanticscholar'); } } }
  }

  // Europe PMC
  if (SRC.europepmc){
    let src='', pid='';
    if (sd){ const q=await get('https://www.ebi.ac.uk/europepmc/webservices/rest/search?query=DOI:%22'+encodeURIComponent(sd)+'%22&format=json&pageSize=1'); const res=q&&q.resultList&&q.resultList.result&&q.resultList.result[0]; if(res){ src=res.source; pid=res.id; } }
    if (!pid && s.title){ const q=await get('https://www.ebi.ac.uk/europepmc/webservices/rest/search?query='+encodeURIComponent('TITLE:"'+s.title.substring(0,120)+'"')+'&format=json&pageSize=1'); const res=q&&q.resultList&&q.resultList.result&&q.resultList.result[0]; if(res){ src=res.source; pid=res.id; } }
    if (src && pid){ resolvedAny=true;
      if (doBack){ const rf=await get('https://www.ebi.ac.uk/europepmc/webservices/rest/'+src+'/'+pid+'/references?format=json&pageSize=200'); const arr=rf&&rf.referenceList&&rf.referenceList.reference; if(arr){ for(const it of arr) addCandidate(mapEPMC(it),'backward',seedLabel,'europepmc'); } }
      if (doFwd){ const ct=await get('https://www.ebi.ac.uk/europepmc/webservices/rest/'+src+'/'+pid+'/citations?format=json&pageSize='+Math.min(FWD_CAP,1000)); const arr=ct&&ct.citationList&&ct.citationList.citation; if(arr){ for(const it of arr) addCandidate(mapEPMC(it),'forward',seedLabel,'europepmc'); } }
    }
  }

  // OpenCitations COCI (DOIs -> enrichis via OpenAlex)
  if (SRC.opencitations && sd){
    if (doBack){ const rf=await get('https://opencitations.net/index/coci/api/v1/references/'+sd); if(Array.isArray(rf)&&rf.length){ resolvedAny=true; await enrichDois(rf.map(function(x){return cleanDoi(x.cited);}).filter(Boolean), 'backward', seedLabel); } }
    if (doFwd){ const ct=await get('https://opencitations.net/index/coci/api/v1/citations/'+sd); if(Array.isArray(ct)&&ct.length){ resolvedAny=true; const ds=ct.map(function(x){return cleanDoi(x.citing);}).filter(Boolean).slice(0,FWD_CAP); await enrichDois(ds, 'forward', seedLabel); } }
  }

  if (resolvedAny) summary.seeds_resolved++;
  else console.log('[Snowball] seed non resolu : ' + seedLabel);
}

// ABSTRACT_CASCADE_v1 : enrichit les abstracts manquants (S2 batch par DOI -> OpenAlex inverted index)
const __enrichAbs = async (arr) => {
  var need = arr.filter(function(a){ return a.doi && (!a.abstract || a.abstract.length < 20); });
  if (!need.length) return 0;
  var done = 0;
  for (var b=0; b<Math.min(need.length,2000); b+=200) {
    var chunk = need.slice(b,b+200).filter(function(a){return !a.abstract||a.abstract.length<20;});
    if (!chunk.length) continue;
    try {
      var resp = await this.helpers.httpRequest({ method:'POST', url:'https://api.semanticscholar.org/graph/v1/paper/batch?fields=abstract', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ ids: chunk.map(function(a){return 'DOI:'+a.doi;}) }), json:true, timeout:90000 });
      if (Array.isArray(resp)) for (var i=0;i<resp.length;i++){ if(resp[i]&&resp[i].abstract&&chunk[i]&&(!chunk[i].abstract||chunk[i].abstract.length<20)){ chunk[i].abstract=resp[i].abstract; chunk[i]._abstract_enriched='semanticscholar'; done++; } }
    } catch(e){ console.log('[Snowball] S2 enrich err: '+(e&&e.message?e.message:e)); }
    await new Promise(function(r){ setTimeout(r,1100); });
  }
  var still = need.filter(function(a){ return !a.abstract || a.abstract.length<20; });
  for (var b2=0; b2<Math.min(still.length,1000); b2+=50) {
    var ch=still.slice(b2,b2+50); var dois=ch.map(function(a){return a.doi;}).filter(Boolean);
    if(!dois.length) continue;
    try {
      var r2=await get('https://api.openalex.org/works?filter=doi:'+dois.join('|')+'&per_page=50&select=doi,abstract_inverted_index');
      if(r2&&r2.results){ var byDoi={}; r2.results.forEach(function(w){ var dd=cleanDoi(w.doi||''); if(dd) byDoi[dd]=recon(w.abstract_inverted_index); }); ch.forEach(function(a){ if((!a.abstract||a.abstract.length<20)&&byDoi[a.doi]){ a.abstract=byDoi[a.doi]; a._abstract_enriched='openalex'; done++; } }); }
    } catch(e){ console.log('[Snowball] OA enrich err: '+(e&&e.message?e.message:e)); }
  }
  return done;
};
let out = Object.keys(store).map(k=>store[k]);
summary.abstracts_enriched = await __enrichAbs(out);
out.sort((a,b)=> ((b._snowball_sources?b._snowball_sources.length:1) - (a._snowball_sources?a._snowball_sources.length:1)) || (b._snowball_seed_count - a._snowball_seed_count) || (b.cited_by_count - a.cited_by_count));
summary.candidates_unique = out.length;
console.log('[Snowball v2] ' + JSON.stringify(summary));

const pass = ['output_folder','_module_mode','_folder_name','_output_format','question','criteria'];
function withPass(o){ for(const k of pass){ if(seed0[k]!==undefined) o[k]=seed0[k]; } return o; }

if (out.length === 0){ return [{ json: withPass({ _snowball_empty:true, _snowball_summary:summary, title:'', authors:[] }) }]; }

const results = out.map(function(c, i){ withPass(c); c.screening_decision=''; if(Array.isArray(c._snowball_sources)) c._snowball_sources_str=c._snowball_sources.join(', '); c._snowball_summary = (i===0)?summary:undefined; return { json:c }; });
return results;
